28	export async function executeCase(
29	  deps: ExecutorDeps,
30	  evalCase: EvalCase,
31	  signal: AbortSignal,
32	): Promise<CaseResult> {
33	  const { loaded, provider, outputDir } = deps;
34	  const retries = loaded.config.execution.retries;
35	  let attempt = 0;
36	  let lastResult: CaseResult | null = null;
37	
38	  await withRetry(
39	    async () => {
40	      attempt += 1;
41	      lastResult = await runOnce(loaded, provider, evalCase, attempt, outputDir, signal);
42	      if (lastResult.status === "errored") throw new Error(lastResult.error ?? "case errored");
43	    },
44	    {
45	      retries,
46	      signal,
47	      onAttempt: (n, err) => log.warn(`retry attempt ${n + 1}`, { err: (err as Error).message }),
48	    },
49	  ).catch(() => undefined);
50	
51	  return lastResult ?? errorResult(evalCase, "execution did not produce a result", attempt);
52	}
