226	function finalize(args: FinalizeArgs): CaseResult {
227	  return {
228	    id: args.evalCase.id,
229	    name: args.evalCase.name ?? args.evalCase.id,
230	    status: args.status,
231	    score: args.score,
232	    duration_ms: args.durationMs,
233	    duration: formatDurationHuman(args.durationMs),
234	    started_at: args.startedAt,
235	    finished_at: nowIso(),
236	    validators: args.validatorResults,
237	    agent_output_summary: summarize(args.agentText),
238	    error: args.error,
239	    metrics: args.metrics,
240	    attempt: args.attempt,
241	  };
242	}
