244	function errorResult(evalCase: EvalCase, message: string, attempt: number): CaseResult {
245	  return {
246	    id: evalCase.id,
247	    name: evalCase.name ?? evalCase.id,
248	    status: "errored",
249	    duration_ms: 0,
250	    duration: "0ms",
251	    started_at: nowIso(),
252	    finished_at: nowIso(),
253	    validators: [],
254	    agent_output_summary: "",
255	    error: message,
256	    metrics: emptyMetrics(),
257	    attempt,
258	  };
259	}
