266	async function saveArtifacts(
267	  sandbox: SandboxHandle,
268	  client: OpenCodeClient,
269	  sessionId: string,
270	  caseDir: string,
271	  signal: AbortSignal,
272	): Promise<void> {
273	  const workspaceDir = join(caseDir, "workspace");
274	  try {
275	    await sandbox.copyWorkdirTo(workspaceDir);
276	  } catch (err) {
277	    log.warn("failed to save workspace", { err: (err as Error).message });
278	  }
279	
280	  try {
281	    const messages = await client.getFullMessages(sessionId, signal);
282	    if (messages) {
283	      await mkdir(caseDir, { recursive: true });
284	      await writeFile(
285	        join(caseDir, "messages.json"),
286	        JSON.stringify(messages, null, 2),
287	        "utf-8",
288	      );
289	    }
290	  } catch (err) {
291	    log.warn("failed to save messages", { err: (err as Error).message });
292	  }
293	}
