301	function buildOpencodeConfig(loaded: LoadedConfig): Record<string, unknown> {
302	  const cfg = loaded.config.opencode;
303	  return {
304	    $schema: "https://opencode.ai/config.json",
305	    model: cfg.model,
306	    provider: cfg.provider,
307	    mcp: cfg.mcp,
308	    permission: cfg.permission,
309	    skills: cfg.skills,
310	    ...(cfg.extra ?? {}),
311	  };
312	}
