314	function collectEnvFromProvider(loaded: LoadedConfig): Record<string, string> {
315	  const env: Record<string, string> = {};
316	  walkForEnv(loaded.config.opencode.provider, env);
317	  if (loaded.config.judge?.api_key_env) {
318	    const v = process.env[loaded.config.judge.api_key_env];
319	    if (v) env[loaded.config.judge.api_key_env] = v;
320	  }
321	  return env;
322	}
323	
324	function walkForEnv(value: unknown, out: Record<string, string>): void {
325	  if (!value || typeof value !== "object") return;
326	  if (Array.isArray(value)) {
327	    for (const v of value) walkForEnv(v, out);
328	    return;
329	  }
330	  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
331	    if ((k === "api_key_env" || k === "apiKeyEnv") && typeof v === "string") {
332	      const resolved = process.env[v];
333	      if (resolved) out[v] = resolved;
334	    } else {
335	      walkForEnv(v, out);
336	    }
337	  }
338	}
