3	const opencodeConfigSchema = z.object({
4	  model: z.string().min(1),
5	  provider: z.record(z.string(), z.unknown()).default({}),
6	  mcp: z.record(z.string(), z.unknown()).default({}),
7	  skills: z.record(z.string(), z.unknown()).default({}),
8	  permission: z.record(z.string(), z.unknown()).default({}),
9	  extra: z.record(z.string(), z.unknown()).optional(),
10	});
11	
12	const executionConfigSchema = z.object({
13	  concurrency: z.number().int().positive().default(4),
14	  case_timeout_ms: z.number().int().positive().default(300_000),
15	  global_timeout_ms: z.number().int().positive().default(3_600_000),
16	  retries: z.number().int().min(0).max(5).default(0),
17	  fail_fast: z.boolean().default(false),
18	});
19	
20	const scoringDimensionSchema = z.object({
21	  name: z.string().min(1),
22	  weight: z.number().min(0).default(1),
23	  description: z.string().optional(),
24	});
25	
26	const scoringConfigSchema = z.object({
27	  scale: z.number().int().positive().default(10),
28	  pass_threshold: z.number().min(0).default(6),
29	  dimensions: z.array(scoringDimensionSchema).min(1),
30	});
31	
32	const judgeConfigSchema = z
33	  .object({
34	    type: z.enum(["anthropic", "openai_compatible"]).default("openai_compatible"),
35	    model: z.string().min(1),
36	    base_url: z.string().url().optional(),
37	    api_key: z.string().optional(),
38	    api_key_env: z.string().optional(),
39	    temperature: z.number().min(0).max(2).default(0),
40	    rubric: z.string().optional(),
41	    max_tokens: z.number().int().positive().default(8192),
42	    extra_headers: z.record(z.string(), z.string()).default({}),
43	    scoring: scoringConfigSchema,
44	  })
45	  .superRefine((v, ctx) => {
46	    if (v.type === "openai_compatible" && !v.base_url) {
47	      ctx.addIssue({
48	        code: z.ZodIssueCode.custom,
49	        message: "openai_compatible judge requires `base_url`",
50	        path: ["base_url"],
51	      });
52	    }
53	  });
54	
55	export const evalConfigSchema = z.object({
56	  name: z.string().min(1),
57	  description: z.string().optional(),
58	  opencode: opencodeConfigSchema,
59	  execution: executionConfigSchema.default({}),
60	  judge: judgeConfigSchema.optional(),
61	  dataset: z.string().min(1).default("./dataset.json"),
62	});
63	
64	export type EvalConfig = z.infer<typeof evalConfigSchema>;
65	export type OpenCodeConfig = z.infer<typeof opencodeConfigSchema>;
66	export type ExecutionConfig = z.infer<typeof executionConfigSchema>;
67	export type JudgeConfig = z.infer<typeof judgeConfigSchema>;
68	export type ScoringConfig = z.infer<typeof scoringConfigSchema>;
69	export type ScoringDimension = z.infer<typeof scoringDimensionSchema>;
